module RefModule(
  input [31:0] dividend,
  input [31:0] divisor,
  output reg [31:0] remainder
);// Calculate the unused_quotient
  reg [31:0] unused_quotient;
  assign unused_quotient = dividend / divisor;

  // Calculate the product of the unused_quotient and the divisor
  reg [31:0] product;
  assign product = unused_quotient * divisor;

  // Subtract the product from the dividend to get the remainder
  always @(*) begin
    remainder = dividend - product;
  end

endmodule
